<?php declare(strict_types=1);
namespace SkyFi\System\Repositories;
use SkyFi\System\Contracts\LocalizationRepositoryContract;
final class PdoLocalizationRepository extends PdoSystemRepository implements LocalizationRepositoryContract { private array $allowed=['default_language','supported_languages','default_timezone','supported_timezones','default_currency','supported_currencies','date_format','time_format','number_format','first_day_of_week']; private array $json=['supported_languages','supported_timezones','supported_currencies','number_format']; public function first(): array { return $this->singleton('localization_settings', self::defaults(), $this->json); } public function update(array $data, ?int $userId=null): array { return $this->updateSingleton('localization_settings',$data,self::defaults(),$this->allowed,$this->json,$userId); } public function options(): array { return ['languages'=>['en','ur','ar'],'timezones'=>['Asia/Karachi','UTC','Asia/Dubai','Europe/London','America/New_York'],'currencies'=>['PKR','USD','AED','GBP','EUR'],'date_formats'=>['YYYY-MM-DD','DD/MM/YYYY','MM/DD/YYYY','DD MMM YYYY']]; } public static function defaults(): array { return ['default_language'=>'en','supported_languages'=>['en'],'default_timezone'=>'Asia/Karachi','supported_timezones'=>['Asia/Karachi','UTC'],'default_currency'=>'PKR','supported_currencies'=>['PKR'],'date_format'=>'YYYY-MM-DD','time_format'=>'HH:mm','number_format'=>['decimal_separator'=>'.','thousand_separator'=>',','precision'=>2],'first_day_of_week'=>1]; }}
